#chart-wrap {
  max-width: 650px;
  position: relative;
  margin: 35px auto;
}

#chart {
  padding-bottom: 30px;
  max-width: 650px;
}

.legend {
  max-width: 650px;
  left: 80px;
  bottom: 20px;
  position: absolute;
  text-align: center;
  margin: 0 auto;
}

/* The check icon fill/stroke used to live in an inline style attribute on each
   path; a class keeps the html valid for the JSX (React) and Vue builds too. */
.legend .svg-icon path {
  stroke: #fff;
  fill: #fff;
}
